mapper.select:
select h.id, h.biz_type, h.usage_id, h.oper_type, h.change_time, h.change_by,
       ifnull(nullif(trim(su.nick_name), ''), h.change_by) as change_by_nick,
       h.before_json, h.after_json, h.remark
from cst_report_usage_hist h
left join sys_user su on h.change_by = su.user_name and su.del_flag = '0'

     and h.biz_type = #{bizType}
     and h.usage_id = #{usageId}
     and h.oper_type = #{operType}
     and h.change_by = #{changeBy}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.statDate')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.statDate'))) >= #{reportBegin}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.statDate')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.statDate'))) <= #{reportEnd}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.reportDate')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.reportDate'))) >= #{reportBegin}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.reportDate')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.reportDate'))) <= #{reportEnd}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.equipType')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.equipType'))) = #{equipType}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.useDept')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.useDept'))) = #{useDept}


        and ifnull(nullif(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.useDept')), ''),
            JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.useDept'))) = #{useDept}


        and (
            ifnull(JSON_UNQUOTE(JSON_EXTRACT(h.after_json, '$.equipDesc')), '') like concat('%', #{equipDesc}, '%')
            or ifnull(JSON_UNQUOTE(JSON_EXTRACT(h.before_json, '$.equipDesc')), '') like concat('%', #{equipDesc}, '%')
        )


        and h.change_time >= #{params.beginTime}


        and h.change_time <= concat(#{params.endTime}, ' 23:59:59')


order by h.change_time desc, h.id desc
